import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import './App.css';

const AuthScreen = ({ onLogin, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');
  const [name, setName] = useState('');

  return (
    <div className="login-page">
      <div className="login-card fade-in">
        <h2>{isLogin ? 'Вход' : 'Регистрация'}</h2>
        {!isLogin && <input type="text" placeholder="Имя" onChange={e => setName(e.target.value)} />}
        <input type="email" placeholder="Email" onChange={e => setEmail(e.target.value)} />
        <input type="password" placeholder="Пароль" onChange={e => setPass(e.target.value)} />
        <button className="btn-main" onClick={() => isLogin ? onLogin(email, pass) : onRegister(name, email, pass)}>
          {isLogin ? 'Войти' : 'Создать аккаунт'}
        </button>
        <p className="toggle-auth" onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Нет аккаунта? Создать' : 'Уже есть аккаунт? Войти'}
        </p>
      </div>
    </div>
  );
};

const Menu = ({ onOrder }) => {
  const items = [{ id: 1, name: 'Капучино', price: 250, img: '☕' }, { id: 2, name: 'Латте', price: 280, img: '🥛' }, { id: 3, name: 'Круассан', price: 210, img: '🥐' }];
  return (
    <div className="page">
      <h2>Меню</h2>
      <div className="product-grid">
        {items.map(i => (
          <div key={i.id} className="product-card" onClick={() => onOrder(i)}>
            <span style={{fontSize: '40px'}}>{i.img}</span>
            <h3>{i.name}</h3>
            <p>{i.price} ₽</p>
          </div>
        ))}
      </div>
    </div>
  );
};

const Profile = ({ user, orders, onLogout }) => (
  <div className="page">
    <div className="user-info-card">
      <h3>{user?.company_name}</h3>
      <button onClick={onLogout} className="btn-logout">Выйти</button>
    </div>
    <h3>Мои заказы</h3>
    <div className="order-history">
      {orders.map(o => (
        <div key={o.id} className={`order-item ${o.status === 'Готов' ? 'ready' : ''}`}>
          <span>#{o.id} - {o.description}</span>
          <span className="status-label">{o.status}</span>
        </div>
      ))}
    </div>
  </div>
);

export default function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    if (!user) return;
    const fetchOrders = () => {
      fetch(`http://localhost:8000/index.php?user_id=${user.id}`)
        .then(res => res.json()).then(data => setOrders(Array.isArray(data) ? data : []));
    };
    fetchOrders();
    const int = setInterval(fetchOrders, 3000);
    return () => clearInterval(int);
  }, [user]);

  const login = async (email, password) => {
    const res = await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ action: 'login', email, password })});
    const data = await res.json();
    if (data.id) { setUser(data); localStorage.setItem('user', JSON.stringify(data)); } else { alert(data.error); }
  };

  const register = async (name, email, password) => {
    const res = await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ action: 'register', name, email, password })});
    const data = await res.json();
    if (data.id) { setUser(data); localStorage.setItem('user', JSON.stringify(data)); } else { alert(data.error); }
  };

  const handleOrder = async (item) => {
    await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ user_id: user.id, description: item.name, total_amount: item.price })});
    alert('Заказ принят!');
  };

  if (!user) return <AuthScreen onLogin={login} onRegister={register} />;

  return (
    <Router>
      <div className="paradise-app">
        <Routes>
          <Route path="/" element={<Menu onOrder={handleOrder} />} />
          <Route path="/profile" element={<Profile user={user} orders={orders} onLogout={() => {setUser(null); localStorage.removeItem('user');}} />} />
        </Routes>
        <nav className="bottom-nav">
          <Link to="/">🍴 Меню</Link>
          <Link to="/profile">👤 Профиль</Link>
        </nav>
      </div>
    </Router>
  );
}
